export function normalizeAcademicTerm(value: string): string {
  return value.toLowerCase().replace(/[\s　]/g, '').replace(/[，、。,.]/g, '')
}
export const normalizedAcademicConcreteTerms = new Set<string>(Array.from(academicConcreteTerms).map(normalizeAcademicTerm))
export function isRegisteredAcademicTerm(value: string): boolean {
  const normalized = normalizeAcademicTerm(value)
  if (!normalized || normalized.length < 2) return false
  return normalizedAcademicConcreteTerms.has(normalized)
}
